const Fraction = require('fraction.js');

function toFraction(frac) {

  var map = {
    '1:4': "횂쩌",
    '1:2': "횂쩍",
    '3:4': "횂쩐",
    '1:7': "창혚혨",
    '1:9': "창혚혩",
    '1:10': "창혚혪",
    '1:3': "창혚혫",
    '2:3': "창혚혬",
    '1:5': "창혚혮",
    '2:5': "창혚혯",
    '3:5': "창혚혰",
    '4:5': "창혚혱",
    '1:6': "창혚혲",
    '5:6': "창혚혳",
    '1:8': "창혚혴",
    '3:8': "창혚혵",
    '5:8': "창혚혶",
    '7:8': "창혚혷"
  };
  return map[frac.n + ":" + frac.d] || frac.toFraction(false);
}
console.log(toFraction(Fraction(0.25))); // 횂쩌
